   233→func (mg *Migrator) run(ctx context.Context) (err error) {
   234→	ctx, span := tracer.Start(ctx, "Migrator.run")
   235→	defer span.End()
   236→
   237→	logger := mg.Logger.FromContext(ctx)
   238→
   239→	logger.Info("Starting DB migrations")
   240→
   241→	migrationLogExists, err := mg.DBEngine.IsTableExist(mg.tableName)
   242→	if err != nil {
   243→		return fmt.Errorf("failed to check table existence: %w", err)
   244→	}
   245→
   246→	if !migrationLogExists {
   247→		// Check if dialect can initialize database from a snapshot.
   248→		err := mg.Dialect.CreateDatabaseFromSnapshot(ctx, mg.DBEngine, mg.tableName)
   249→		if err != nil {
   250→			return fmt.Errorf("failed to create database from snapshot: %w", err)
   251→		}
   252→
   253→		migrationLogExists, err = mg.DBEngine.IsTableExist(mg.tableName)
   254→		if err != nil {
   255→			return fmt.Errorf("failed to check table existence after applying snapshot: %w", err)
   256→		}
   257→	}
   258→
   259→	if migrationLogExists {
   260→		_, err = mg.GetMigrationLog()
   261→		if err != nil {
   262→			return err
   263→		}
   264→	}
   265→
   266→	successLabel := prometheus.Labels{"success": "true"}
   267→
   268→	migrationsPerformed := 0
   269→	migrationsSkipped := 0
   270→	start := time.Now()
   271→	for _, m := range mg.migrations {
   272→		_, exists := mg.logMap[m.Id()]
   273→		if exists {
   274→			logger.Debug("Skipping migration: Already executed", "id", m.Id())
   275→			span.AddEvent("Skipping migration: Already executed",
   276→				trace.WithAttributes(attribute.String("migration_id", m.Id())),
   277→			)
   278→			migrationsSkipped++
   279→			continue
   280→		}
   281→
   282→		migStart := time.Now()
   283→
   284→		if err := mg.doMigration(ctx, m); err != nil {
   285→			failLabel := prometheus.Labels{"success": "false"}
   286→			metricutil.ObserveWithExemplar(ctx, mg.metrics.migDuration.With(failLabel), time.Since(migStart).Seconds())
   287→			mg.metrics.migCount.With(failLabel).Inc()
   288→			return err
   289→		}
   290→
   291→		metricutil.ObserveWithExemplar(ctx, mg.metrics.migDuration.With(successLabel), time.Since(migStart).Seconds())
   292→		mg.metrics.migCount.With(successLabel).Inc()
   293→
   294→		migrationsPerformed++
   295→	}
   296→
   297→	metricutil.ObserveWithExemplar(ctx, mg.metrics.totalMigDuration.With(successLabel), time.Since(start).Seconds())
   298→
   299→	logger.Info("migrations completed", "performed", migrationsPerformed, "skipped", migrationsSkipped, "duration", time.Since(start))
   300→
   301→	// Make sure migrations are synced
   302→	return mg.DBEngine.Sync2()
   303→}
