   188→	return mg.RunMigrations(context.Background(), isDatabaseLockingEnabled, lockAttemptTimeout)
   189→}
   190→
   191→func (mg *Migrator) RunMigrations(ctx context.Context, isDatabaseLockingEnabled bool, lockAttemptTimeout int) (err error) {
   192→	if !isDatabaseLockingEnabled {
   193→		return mg.run(ctx)
   194→	}
   195→
   196→	dbName, err := mg.Dialect.GetDBName(mg.DBEngine.DataSourceName())
   197→	if err != nil {
   198→		return err
   199→	}
   200→	key, err := database.GenerateAdvisoryLockId(dbName)
   201→	if err != nil {
   202→		return err
   203→	}
   204→
   205→	logger := mg.Logger.FromContext(ctx)
   206→
   207→	return mg.InTransaction(func(sess *xorm.Session) error {
   208→		logger.Info("Locking database")
   209→		lockCfg := LockCfg{
   210→			Session: sess,
   211→			Key:     key,
   212→			Timeout: lockAttemptTimeout,
   213→		}
   214→
   215→		if err := casRestoreOnErr(&mg.isLocked, false, true, ErrMigratorIsLocked, mg.Dialect.Lock, lockCfg); err != nil {
   216→			logger.Error("Failed to lock database", "error", err)
   217→			return err
   218→		}
   219→
   220→		defer func() {
   221→			logger.Info("Unlocking database")
   222→			unlockErr := casRestoreOnErr(&mg.isLocked, true, false, ErrMigratorIsUnlocked, mg.Dialect.Unlock, lockCfg)
   223→			if unlockErr != nil {
   224→				logger.Error("Failed to unlock database", "error", unlockErr)
   225→			}
   226→		}()
   227→
   228→		// migration will run inside a nested transaction
   229→		return mg.run(ctx)
   230→	})
   231→}
   232→
   233→func (mg *Migrator) run(ctx context.Context) (err error) {
   234→	ctx, span := tracer.Start(ctx, "Migrator.run")
   235→	defer span.End()
   236→
   237→	logger := mg.Logger.FromContext(ctx)
   238→
   239→	logger.Info("Starting DB migrations")
   240→
   241→	migrationLogExists, err := mg.DBEngine.IsTableExist(mg.tableName)
   242→	if err != nil {
   243→		return fmt.Errorf("failed to check table existence: %w", err)
   244→	}
   245→
   246→	if !migrationLogExists {
   247→		// Check if dialect can initialize database from a snapshot.
   248→		err := mg.Dialect.CreateDatabaseFromSnapshot(ctx, mg.DBEngine, mg.tableName)
   249→		if err != nil {
   250→			return fmt.Errorf("failed to create database from snapshot: %w", err)
   251→		}
   252→
   253→		migrationLogExists, err = mg.DBEngine.IsTableExist(mg.tableName)
   254→		if err != nil {
   255→			return fmt.Errorf("failed to check table existence after applying snapshot: %w", err)
   256→		}
   257→	}
   258→
   259→	if migrationLogExists {
   260→		_, err = mg.GetMigrationLog()
   261→		if err != nil {
   262→			return err
   263→		}
   264→	}
   265→
   266→	successLabel := prometheus.Labels{"success": "true"}
   267→
   268→	migrationsPerformed := 0
   269→	migrationsSkipped := 0
   270→	start := time.Now()
   271→	for _, m := range mg.migrations {
   272→		_, exists := mg.logMap[m.Id()]
   273→		if exists {
   274→			logger.Debug("Skipping migration: Already executed", "id", m.Id())
   275→			span.AddEvent("Skipping migration: Already executed",
   276→				trace.WithAttributes(attribute.String("migration_id", m.Id())),
   277→			)
   278→			migrationsSkipped++
   279→			continue
   280→		}
   281→
   282→		migStart := time.Now()
   283→
   284→		if err := mg.doMigration(ctx, m); err != nil {
   285→			failLabel := prometheus.Labels{"success": "false"}
   286→			metricutil.ObserveWithExemplar(ctx, mg.metrics.migDuration.With(failLabel), time.Since(migStart).Seconds())
   287→			mg.metrics.migCount.With(failLabel).Inc()
   288→			return err
   289→		}
   290→
   291→		metricutil.ObserveWithExemplar(ctx, mg.metrics.migDuration.With(successLabel), time.Since(migStart).Seconds())
   292→		mg.metrics.migCount.With(successLabel).Inc()
   293→
   294→		migrationsPerformed++
   295→	}
   296→
   297→	metricutil.ObserveWithExemplar(ctx, mg.metrics.totalMigDuration.With(successLabel), time.Since(start).Seconds())
   298→
   299→	logger.Info("migrations completed", "performed", migrationsPerformed, "skipped", migrationsSkipped, "duration", time.Since(start))
   300→
   301→	// Make sure migrations are synced
   302→	return mg.DBEngine.Sync2()
   303→}
   304→
   305→func (mg *Migrator) doMigration(ctx context.Context, m Migration) error {
   306→	ctx, span := tracer.Start(ctx, "Migrator.doMigration", trace.WithAttributes(
   307→		attribute.String("migration_id", m.Id()),
   308→	))
   309→	defer span.End()
   310→
   311→	logger := mg.Logger.FromContext(ctx)
   312→
   313→	sql := m.SQL(mg.Dialect)
   314→
   315→	record := MigrationLog{
   316→		MigrationID: m.Id(),
   317→		SQL:         sql,
   318→		Timestamp:   time.Now(),
   319→	}
   320→
   321→	err := mg.InTransaction(func(sess *xorm.Session) error {
   322→		// propagate context
   323→		sess = sess.Context(ctx)
   324→
   325→		err := mg.exec(ctx, m, sess)
   326→		// if we get an sqlite busy/locked error, sleep 100ms and try again
   327→		cnt := 0
   328→		for cnt < 3 && sqlite.IsBusyOrLocked(err) {
   329→			cnt++
   330→			logger.Debug("Database locked, sleeping then retrying", "error", err, "sql", sql)
   331→			span.AddEvent("Database locked, sleeping then retrying",
   332→				trace.WithAttributes(attribute.String("error", err.Error())),
   333→				trace.WithAttributes(attribute.String("sql", sql)),
   334→			)
   335→			time.Sleep(100 * time.Millisecond)
   336→			err = mg.exec(ctx, m, sess)
   337→		}
   338→
   339→		if err != nil {
   340→			logger.Error("Exec failed", "error", err, "sql", sql)
   341→			record.Error = err.Error()
   342→			if !m.SkipMigrationLog() {
   343→				if _, err := sess.Table(mg.tableName).Insert(&record); err != nil {
   344→					return err
   345→				}
   346→			}
   347→			return err
   348→		}
   349→		record.Success = true
   350→		if !m.SkipMigrationLog() {
   351→			_, err = sess.Table(mg.tableName).Insert(&record)
   352→		}
   353→		return err
   354→	})
   355→	if err != nil {
   356→		return tracing.Errorf(span, "migration failed (id = %s): %w", m.Id(), err)
   357→	}
   358→
   359→	span.SetStatus(codes.Ok, "")
   360→
   361→	return nil
   362→}
   363→
   364→func (mg *Migrator) exec(ctx context.Context, m Migration, sess *xorm.Session) error {
   365→	logger := mg.Logger.FromContext(ctx)
   366→
   367→	start := time.Now()
   368→	logger.Info("Executing migration", "id", m.Id())
   369→
   370→	condition := m.GetCondition()
   371→	if condition != nil {
   372→		sql, args := condition.SQL(mg.Dialect)
   373→
   374→		if sql != "" {
   375→			logger.Debug("Executing migration condition SQL", "id", m.Id(), "sql", sql, "args", args)
   376→			results, err := sess.SQL(sql, args...).Query()
   377→			if err != nil {
   378→				logger.Error("Executing migration condition failed", "id", m.Id(), "error", err)
   379→				return err
   380→			}
   381→
   382→			if !condition.IsFulfilled(results) {
   383→				logger.Warn("Skipping migration: Already executed, but not recorded in migration log", "id", m.Id())
   384→				return nil
   385→			}
   386→		}
   387→	}
   388→
   389→	var err error
   390→	if codeMigration, ok := m.(CodeMigration); ok {
   391→		logger.Debug("Executing code migration", "id", m.Id())
   392→		err = codeMigration.Exec(sess, mg)
   393→	} else {
   394→		sql := m.SQL(mg.Dialect)
   395→		if strings.TrimSpace(sql) == "" {
   396→			logger.Debug("Skipping empty sql migration", "id", m.Id())
   397→		} else {
   398→			logger.Debug("Executing sql migration", "id", m.Id(), "sql", sql)
   399→			_, err = sess.Exec(sql)
   400→		}
   401→	}
   402→
   403→	if err != nil {
   404→		logger.Error("Executing migration failed", "id", m.Id(), "error", err, "duration", time.Since(start))
   405→		return err
   406→	}
   407→
   408→	logger.Info("Migration successfully executed", "id", m.Id(), "duration", time.Since(start))
   409→
   410→	return nil
   411→}
   412→
   413→type dbTransactionFunc func(sess *xorm.Session) error
   414→
   415→func (mg *Migrator) InTransaction(callback dbTransactionFunc) error {
   416→	sess := mg.DBEngine.NewSession()
   417→	defer sess.Close()
   418→
   419→	if err := sess.Begin(); err != nil {
   420→		return err
   421→	}
   422→
   423→	if err := callback(sess); err != nil {
   424→		if rollErr := sess.Rollback(); rollErr != nil {
   425→			return fmt.Errorf("failed to roll back transaction due to error: %s: %w", rollErr, err)
   426→		}
   427→
   428→		return err
   429→	}
   430→
   431→	if err := sess.Commit(); err != nil {
   432→		return err
   433→	}
   434→
   435→	return nil
   436→}
   437→
   438→func casRestoreOnErr(lock *atomic.Bool, o, n bool, casErr error, f func(LockCfg) error, lockCfg LockCfg) error {
   439→	if !lock.CompareAndSwap(o, n) {
   440→		return casErr
   441→	}
   442→	if err := f(lockCfg); err != nil {
   443→		// Automatically unlock/lock on error
   444→		lock.Store(o)
   445→		return err
   446→	}
   447→	return nil
   448→}
   449→

