   121→	Postgres:               NewPostgresDialect,
   122→	MySQL + "WithHooks":    NewMysqlDialect,
   123→	SQLite + "WithHooks":   NewSQLite3Dialect,
   124→	Postgres + "WithHooks": NewPostgresDialect,
   125→}
