   153→	param := pattern
   154→	if wildcardBefore {
   155→		param = "%" + param
   156→	}
   157→	if wildcardAfter {
   158→		param = param + "%"
   159→	}
   160→	return fmt.Sprintf("%s LIKE ?", column), param
   161→}
