   387→func (b *BaseDialect) InsertQuery(tableName string, row map[string]any) (string, []any, error) {
   388→	if len(row) < 1 {
   389→		return "", nil, fmt.Errorf("no columns provided")
   390→	}
   391→
   392→	// allocate slices
   393→	cols := make([]string, 0, len(row))
   394→	vals := make([]any, 0, len(row))
   395→	keys := make([]string, 0, len(row))
   396→
   397→	// create sorted list of columns
   398→	for col := range row {
   399→		keys = append(keys, col)
   400→	}
   401→	slices.Sort(keys)
   402→
   403→	// build query and values
   404→	for _, col := range keys {
   405→		cols = append(cols, b.dialect.Quote(col))
   406→		vals = append(vals, row[col])
   407→	}
   408→
   409→	return fmt.Sprintf("INSERT INTO %s (%s) VALUES (%s)", b.dialect.Quote(tableName), strings.Join(cols, ", "), strings.Repeat("?, ", len(row)-1)+"?"), vals, nil
   410→}
   411→
   412→func (b *BaseDialect) UpdateQuery(tableName string, row map[string]any, where map[string]any) (string, []any, error) {
   413→	if len(row) < 1 {
   414→		return "", nil, fmt.Errorf("no columns provided")
   415→	}
   416→
   417→	if len(where) < 1 {
   418→		return "", nil, fmt.Errorf("no where clause provided")
   419→	}
   420→
   421→	// allocate slices
   422→	cols := make([]string, 0, len(row))
   423→	whereCols := make([]string, 0, len(where))
   424→	vals := make([]any, 0, len(row)+len(where))
   425→	keys := make([]string, 0, len(row))
   426→
   427→	// create sorted list of columns to update
   428→	for col := range row {
   429→		keys = append(keys, col)
   430→	}
   431→	slices.Sort(keys)
   432→
   433→	// build update query and values
   434→	for _, col := range keys {
   435→		cols = append(cols, b.dialect.Quote(col)+"=?")
   436→		vals = append(vals, row[col])
   437→	}
   438→
   439→	// create sorted list of columns for where clause
   440→	keys = make([]string, 0, len(where))
   441→	for col := range where {
   442→		keys = append(keys, col)
   443→	}
   444→	slices.Sort(keys)
   445→
   446→	// build where clause and values
   447→	for _, col := range keys {
   448→		whereCols = append(whereCols, b.dialect.Quote(col)+"=?")
   449→		vals = append(vals, where[col])
   450→	}
   451→
   452→	return fmt.Sprintf("UPDATE %s SET %s WHERE %s", b.dialect.Quote(tableName), strings.Join(cols, ", "), strings.Join(whereCols, " AND ")), vals, nil
   453→}
